#include <stdio.h>
#include <math.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int K, C;
        scanf("%d %d", &K, &C);
        int remaining = K * K * K - C;
        int cubeRoot = (int)round(cbrt(remaining));
        if (cubeRoot * cubeRoot * cubeRoot == remaining) {
            printf("YES\n");
        } else {
            printf("NO\n");
        }
    }
    return 0;
}

