code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int K = sc.nextInt();
            int C = sc.nextInt();
            int remaining = K * K * K - C;
            int cubeRoot = (int) Math.round(Math.cbrt(remaining));
            if (cubeRoot * cubeRoot * cubeRoot == remaining) {
                System.out.println("YES");
            } else {
                System.out.println("NO");
            }
        }
    }
}

