const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [K, C] = readline().split(' ').map(Number);
    const remaining = K * K * K - C;
    const cubeRoot = Math.round(remaining ** (1/3));
    if (cubeRoot ** 3 === remaining) {
        console.log('YES');
    } else {
        console.log('NO');
    }
}

